    "code": "import type { IconName } from '@ng-icons/core';\n\nexport interface TreeNode<T> {\n  key: string;\n  label: string;\n  data?: T;\n  icon?: IconName;\n  children?: TreeNode<T>[];\n  expanded?: boolean;\n  selected?: boolean;\n  checked?: boolean;\n  disabled?: boolean;\n  leaf?: boolean;\n}\n\nexport interface TreeNodeTemplateContext<T = unknown> {\n  $implicit: TreeNode<T>;\n  level: number;\n}\n\nexport type TreeCheckState = 'checked' | 'unchecked' | 'indeterminate';\n\nexport interface FlatTreeNode<T> {\n  node: TreeNode<T>;\n  level: number;\n  expandable: boolean;\n  index: number;\n}\n",
